import heapq

def dijkstra(graph, source):
    # graph: dict[node, list[(neighbor, weight)]]
    dist = {source: 0.0}
    pq = [(0.0, source)]
    while pq:
        du, u = heapq.heappop(pq)
        if du > dist.get(u, float('inf')):
            continue
        for v, w in graph.get(u, []):
            nd = du + w
            if nd < dist.get(v, float('inf')):
                dist[v] = nd
                heapq.heappush(pq, (nd, v))
    return dist
